namespace sv_842c3e5be8b544c783a9465f6ca322b5.Client.Auth;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_842c3e5be8b544c783a9465f6ca322b5.Client.Auth;

/// <summary>
/// Client-side AuthenticationStateProvider that reads the persisted user info
/// serialized by the server during static/server rendering. This ensures auth
/// state survives the Server → WebAssembly handoff.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (!persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, authenticationType: nameof(PersistentAuthenticationStateProvider)))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;
using sv_842c3e5be8b544c783a9465f6ca322b5.Client.Auth;

namespace sv_842c3e5be8b544c783a9465f6ca322b5.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that returns a hardcoded authenticated
/// user and persists the user info via PersistentComponentState so the client-side
/// WebAssembly runtime can pick it up after the handoff.
/// </summary>
public sealed class ServerAuthenticationStateProvider : RevalidatingServerAuthenticationStateProvider
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authStateTask;

    public ServerAuthenticationStateProvider(
        ILoggerFactory loggerFactory,
        PersistentComponentState persistentState)
        : base(loggerFactory)
    {
        _persistentState = persistentState;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    private static readonly Claim[] _claims =
    [
        new(ClaimTypes.Name, "bob@example.com"),
        new(ClaimTypes.Email, "bob@example.com"),
        new(ClaimTypes.Role, "User"),
        new(ClaimTypes.Role, "Editor"),
    ];

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var identity = new ClaimsIdentity(_claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);
        return Task.FromResult(new AuthenticationState(user));
    }

    protected override TimeSpan RevalidationInterval => TimeSpan.FromMinutes(30);

    protected override Task<bool> ValidateAuthenticationStateAsync(
        AuthenticationState authenticationState, CancellationToken cancellationToken)
    {
        return Task.FromResult(true);
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> authStateTask)
    {
        _authStateTask = authStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authStateTask ?? GetAuthenticationStateAsync();
        var state = await authState;
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated != true)
            return;

        var email = principal.FindFirst(ClaimTypes.Email)?.Value ?? "";
        var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

        _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
        {
            Email = email,
            Roles = roles,
        });
    }

    protected override void Dispose(bool disposing)
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
        base.Dispose(disposing);
    }
}

